<script>
    function addToFondModal(){
        return {
            addToFondView1: true,
            addToFondSubmit(){
                this.addToFondView1 = false
            }
        }
    }
    function withdrawalModal(){
        return {
            withdrawalView1: true,
            withdrawalSubmit(){
                this.withdrawalView1 = false
            }
        }
    }
    function toggleView() {
        return {
            viewType: 'list',
            showDetailPlanView: false,
            showDetailPlanId: 0,
            totalPlans: 0,

            init() {
                const content = document.getElementById('plansContent');
                if (content) {
                    this.totalPlans = content.querySelectorAll('.fp_block__detail_item').length;
                }
            },

            showDetailPlan: function(planId) {
                this.showDetailPlanView = true
                this.showDetailPlanId = planId
            },
            hideDetailPlan: function() {
                this.showDetailPlanView = false
                this.showDetailPlanId = 0
            },

            get currentIndex() {
                return Number(this.showDetailPlanId.split('_')[1]);
            },

            prevPlan() {
                const prev = this.currentIndex - 1;
                if (prev >= 1) {
                    this.showDetailPlanId = `plan_${prev}`;
                } else {
                    this.showDetailPlanId = `plan_${this.totalPlans}`; // зацикливание
                }
            },

            nextPlan() {
                const next = this.currentIndex + 1;
                if (next <= this.totalPlans) {
                    this.showDetailPlanId = `plan_${next}`;
                } else {
                    this.showDetailPlanId = `plan_1`; // зацикливание
                }
            }
        }
    }
</script>

